using System.ComponentModel;
using Microsoft.Extensions.AI;

// ---------------------------------------------------------------------------
// Tools the agent can invoke
// ---------------------------------------------------------------------------

/// <summary>Simulated web search returning snippet results for a query.</summary>
static class SearchTool
{
    [Description("Search the web for information on a given query. Returns a list of result snippets.")]
    public static string SearchWeb(
        [Description("The search query string")] string query)
    {
        Console.ForegroundColor = ConsoleColor.DarkYellow;
        Console.WriteLine($"  🔍  Searching the web for: \"{query}\"");
        Console.ResetColor();

        // Simulated search results keyed on topic keywords.
        var results = new Dictionary<string, string[]>(StringComparer.OrdinalIgnoreCase)
        {
            ["quantum computing"] =
            [
                "Quantum computing uses qubits that can exist in superpositions of 0 and 1, enabling parallel computation.",
                "Google's Sycamore processor achieved quantum supremacy in 2019 by completing a task in 200 seconds that would take classical supercomputers ~10,000 years.",
                "IBM launched its 1,121-qubit Condor processor in 2023, the largest gate-based quantum processor to date.",
                "Major challenges include qubit decoherence, error correction overhead, and operating at near absolute-zero temperatures.",
                "Potential applications span cryptography, drug discovery, materials science, optimization, and machine learning."
            ],
            ["artificial intelligence"] =
            [
                "AI research began in the 1950s with pioneers like Alan Turing and John McCarthy.",
                "Deep learning breakthroughs since 2012 have driven advances in image recognition, NLP, and generative models.",
                "Large language models (LLMs) such as GPT-4 can generate human-quality text and code.",
                "AI safety and alignment research focuses on ensuring advanced AI systems remain beneficial.",
                "Global AI market size is projected to exceed $1.8 trillion by 2030."
            ],
            ["climate change"] =
            [
                "Global average temperatures have risen ~1.1 °C above pre-industrial levels as of 2023.",
                "The Paris Agreement aims to limit warming to 1.5 °C, requiring net-zero CO₂ emissions by 2050.",
                "Renewable energy capacity additions hit a record 507 GW in 2023, led by solar PV.",
                "Arctic sea ice extent has declined ~13 % per decade since satellite records began in 1979.",
                "Climate tipping points such as ice-sheet collapse and Amazon dieback pose severe risks."
            ]
        };

        // Try to match on any keyword in the query.
        foreach (var (keyword, snippets) in results)
        {
            if (query.Contains(keyword, StringComparison.OrdinalIgnoreCase))
            {
                return string.Join("\n\n", snippets.Select((s, i) => $"[Result {i + 1}] {s}"));
            }
        }

        return $"[Result 1] {query} is an active area of research with many recent developments.\n\n"
             + $"[Result 2] Experts suggest that {query} will have significant impacts across multiple industries.\n\n"
             + $"[Result 3] Recent studies on {query} highlight both opportunities and challenges ahead.";
    }
}

/// <summary>In-memory notebook the agent can write to and read from.</summary>
static class NoteTool
{
    private static readonly List<string> _notes = [];

    [Description("Save a research note for later reference. Use this to record key facts and findings.")]
    public static string SaveNote(
        [Description("The note text to save")] string note)
    {
        _notes.Add(note);
        Console.ForegroundColor = ConsoleColor.DarkCyan;
        Console.WriteLine($"  📝  Note saved (#{_notes.Count})");
        Console.ResetColor();
        return $"Note #{_notes.Count} saved successfully.";
    }

    [Description("Retrieve all saved research notes collected so far.")]
    public static string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes have been saved yet.";

        Console.ForegroundColor = ConsoleColor.DarkCyan;
        Console.WriteLine($"  📖  Reading {_notes.Count} saved note(s)");
        Console.ResetColor();

        return string.Join("\n\n", _notes.Select((n, i) => $"Note #{i + 1}: {n}"));
    }
}

// ---------------------------------------------------------------------------
// Agent loop
// ---------------------------------------------------------------------------

Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       🤖 AI Research Agent           ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY");
if (string.IsNullOrWhiteSpace(apiKey))
{
    Console.ForegroundColor = ConsoleColor.Red;
    Console.WriteLine("Error: Set the OPENAI_API_KEY environment variable to run this agent.");
    Console.ResetColor();
    return 1;
}

var chatTools = new List<AITool>
{
    AIFunctionFactory.Create(SearchTool.SearchWeb),
    AIFunctionFactory.Create(NoteTool.SaveNote),
    AIFunctionFactory.Create(NoteTool.GetNotes),
};

IChatClient client = new ChatClientBuilder(
        new OpenAI.OpenAIClient(apiKey).GetChatClient("gpt-4o-mini").AsIChatClient())
    .UseFunctionInvocation()
    .Build();

var systemPrompt = """
    You are a research assistant. When the user provides a topic:
    1. Use the SearchWeb tool to find relevant information (make multiple searches with varied queries).
    2. Use SaveNote to record each important finding as a separate note.
    3. After gathering enough information, use GetNotes to review everything you collected.
    4. Finally, provide a well-structured summary of your research to the user.
    Always search before answering. Be thorough and cite specific facts.
    """;

var chatHistory = new List<ChatMessage>
{
    new(ChatRole.System, systemPrompt)
};

Console.Write("Enter a research topic (or 'quit' to exit): ");
while (Console.ReadLine() is { } input)
{
    input = input.Trim();
    if (string.Equals(input, "quit", StringComparison.OrdinalIgnoreCase) || input.Length == 0)
        break;

    chatHistory.Add(new ChatMessage(ChatRole.User, $"Research the following topic and provide a summary: {input}"));

    Console.WriteLine();
    Console.ForegroundColor = ConsoleColor.DarkGray;
    Console.WriteLine("Agent is researching…");
    Console.ResetColor();

    var response = await client.GetResponseAsync(chatHistory, new ChatOptions { Tools = chatTools });

    // Append the assistant response(s) to history.
    foreach (var msg in response.Messages)
        chatHistory.Add(msg);

    Console.WriteLine();
    Console.ForegroundColor = ConsoleColor.Green;
    Console.WriteLine("── Research Summary ─────────────────────────");
    Console.ResetColor();

    // Print the final assistant text.
    var finalText = response.Messages
        .Where(m => m.Role == ChatRole.Assistant && !string.IsNullOrWhiteSpace(m.Text))
        .Select(m => m.Text)
        .LastOrDefault();

    Console.WriteLine(finalText ?? "(no summary produced)");
    Console.WriteLine();
    Console.Write("Enter a research topic (or 'quit' to exit): ");
}

Console.WriteLine("Goodbye!");
return 0;

